mapper.select:
SELECT t.*, c.title as competition_title, u.real_name as leader_name, (SELECT COUNT(*) FROM team_member tm WHERE tm.team_id = t.id) as current_members FROM team t LEFT JOIN competition c ON t.competition_id = c.id LEFT JOIN user u ON t.leader_id = u.id
AND t.competition_id = #{competitionId}
AND t.status = #{status}
ORDER BY t.create_time DESC

mapper.update:
UPDATE team
name = #{name}, max_members = #{maxMembers}, status = #{status},
WHERE id = #{id}
